package z_pkg;
   localparam int SIZEW=4;
   localparam int CLINE_DATAW=512;

  typedef logic [SIZEW-1:0]     size_t;
   typedef enum {
      TXN_UNSET,
      TXN_GET
   } txn_type_t;
endpackage

import z_pkg::*;

class z_txn;
   rand txn_type_t   req_txn_type;
   rand size_t       size;

   static function z_txn generate_txn(txn_type_t txn_type);
      z_txn txn = new;
      int success = txn.randomize() with {
         req_txn_type == txn_type;
	 size         <= size_t'($clog2(CLINE_DATAW/8));
      };
      assert(success != 0);
      // txn.req_opcode = txn_opcode(txn_type);
      return txn;
   endfunction
endclass

module t;
endmodule
